import React from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer } from 'recharts';
import { motion } from 'framer-motion';

const skillsData = [
  { name: 'Windows App Dev', value: 90 },
  { name: 'Microsoft Office', value: 90 },
  { name: 'Database Design', value: 80 },
  { name: 'Adobe Photoshop', value: 70 },
  { name: 'Video Editing', value: 65 },
  { name: 'Mobile/Web App', value: 60 },
  { name: 'Linux OS', value: 45 },
];

const COLORS = ['#FFD700', '#333333']; // Electric Gold vs Dark Gray

const SkillGauge: React.FC<{ name: string; value: number; delay: number }> = ({ name, value, delay }) => {
  const data = [
    { name: 'Skill', value: value },
    { name: 'Remaining', value: 100 - value },
  ];

  return (
    <motion.div
      initial={{ opacity: 0, scale: 0.9 }}
      whileInView={{ opacity: 1, scale: 1 }}
      viewport={{ once: true }}
      transition={{ duration: 0.5, delay }}
      className="flex flex-col items-center p-4 bg-surface/50 rounded-xl border border-white/5 hover:border-white/10 transition-all"
    >
      <div className="relative w-32 h-32">
        <ResponsiveContainer width="100%" height="100%">
          <PieChart>
            <Pie
              data={data}
              cx="50%"
              cy="50%"
              innerRadius={45}
              outerRadius={55}
              startAngle={180}
              endAngle={-180}
              dataKey="value"
              stroke="none"
              cornerRadius={10}
            >
              <Cell key={`cell-0`} fill={COLORS[0]} />
              <Cell key={`cell-1`} fill={COLORS[1]} />
            </Pie>
          </PieChart>
        </ResponsiveContainer>
        <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
          <span className="text-2xl font-bold text-white">{value}%</span>
        </div>
      </div>
      <h4 className="mt-2 text-center font-medium text-gray-300">{name}</h4>
    </motion.div>
  );
};

const Skills: React.FC = () => {
  return (
    <section id="skills" className="py-20 bg-charcoal relative">
