const SkillCard: React.FC<{ skill: {name: string, value: number, color: string, description: string}, index: number }> = ({ skill, index }) => {
    const [isHovered, setIsHovered] = useState(false);

    return (
        <motion.div 
            initial={{ opacity: 0, scale: 0.95 }}
            whileInView={{ opacity: 1, scale: 1 }}
            viewport={{ once: true }}
            transition={{ delay: index * 0.05 }}
            className="relative p-8 border-r border-b border-border group hover:bg-void-light transition-colors z-10 hover:z-20"
            onMouseEnter={() => setIsHovered(true)}
            onMouseLeave={() => setIsHovered(false)}
        >
            <div className="flex justify-between items-start mb-12">
                 <span className="text-xs font-mono text-gray-600 group-hover:text-white transition-colors">0{index + 1}</span>
                 <div className="w-2 h-2 rounded-full transition-colors duration-300" style={{ backgroundColor: skill.color }}></div>
            </div>

            <h3 className="text-lg font-bold text-white mb-4">{skill.name}</h3>

            <div className="w-full bg-white/5 h-1.5 mt-auto rounded-full overflow-hidden">
                <motion.div 
                    initial={{ width: 0 }}
                    whileInView={{ width: `${skill.value}%` }}
                    viewport={{ once: true }}
                    transition={{ 
                        type: "spring", 
                        stiffness: 50, 
                        damping: 10, 
                        mass: 0.8,
                        delay: index * 0.1 
                    }}
                    className="h-full relative"
                    style={{ backgroundColor: skill.color }}
                >
                    <div className="absolute right-0 top-0 bottom-0 w-2 bg-white/50 blur-[2px]"></div>
                </motion.div>
            </div>
            <div className="mt-3 flex justify-between items-center">
                <div className="text-xs font-mono text-gray-500">PROFIENCY</div>
                <div className="text-sm font-bold" style={{ color: skill.color }}>{skill.value}%</div>
            </div>

            {/* Hover Glow Effect */}
            <div className="absolute inset-0 bg-gradient-to-br from-white/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none"></div>

            {/* Tooltip */}
            <AnimatePresence>
                {isHovered && (
                    <motion.div
                        initial={{ opacity: 0, y: 15, scale: 0.95, rotateX: 10 }}
                        animate={{ opacity: 1, y: 0, scale: 1, rotateX: 0 }}
