              />
            </a>
          </div>

          {/* Desktop Navigation */}
          <nav className="hidden md:flex items-center h-full flex-grow justify-end">
            {navLinks.map((link) => (
              <a
                key={link.name}
                href={link.href}
                className="h-full flex items-center px-8 text-sm font-medium text-gray-400 hover:text-white hover:bg-white/5 border-l border-border transition-colors uppercase tracking-wider"
              >
                {link.name}
              </a>
            ))}

            {/* Theme Toggle */}
