                {isDark ? (
                    <Sun className="w-5 h-5 text-gray-400 group-hover:text-acid transition-colors" />
                ) : (
                    <Moon className="w-5 h-5 text-gray-400 group-hover:text-acid transition-colors" />
                )}
            </button>

            <a
              href="#contact"
              className="h-full flex items-center gap-2 px-8 text-sm font-bold text-void bg-acid hover:bg-white hover:text-void border-l border-border transition-colors uppercase tracking-wider"
