    const interval = setInterval(() => {
        const currentIndex = services.findIndex(s => s.id === activeId);
        const nextIndex = (currentIndex + 1) % services.length;
        setActiveId(services[nextIndex].id);
    }, 5000);
    return () => clearInterval(interval);
