    // Start from top (-Math.PI / 2) but shift by (Math.PI / total) so no item is directly at 12 o'clock
    const angle = (index / total) * 2 * Math.PI - Math.PI / 2 + (Math.PI / total); 
    return {
      x: Math.cos(angle) * radius,
      y: Math.sin(angle) * radius
    };
  };

