                                        ${isActive ? `${service.borderColor} bg-white/10` : 'border-white/10 bg-transparent'}
                                     `}>
                                         <div className={isActive ? service.color : 'text-gray-400'}>
                                             {service.icon}
                                         </div>
                                     </div>
                                 </button>
                             )
                         })}
                    </div>
                </div>

            </div>

        </div>
    </section>
  );
};

