// --- Scramble Text Component ---
const ScrambleText: React.FC<{ text: string; className?: string; delay?: number }> = ({ text, className, delay = 0 }) => {
  const [display, setDisplay] = useState("");
  const [isScrambling, setIsScrambling] = useState(false);
  // A mix of uppercase, numbers, and symbols for a "cyber" feel
  const chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789_@#&[]";

  const scramble = () => {
    if (isScrambling) return;
    setIsScrambling(true);
    let iterations = 0;

    // Fill with random initial chars if empty
    if(display === "") {
        setDisplay(Array(text.length).fill("0").map(() => chars[Math.floor(Math.random() * chars.length)]).join(""));
    }

    const interval = setInterval(() => {
      setDisplay(
        text
          .split("")
          .map((letter, index) => {
            if (index < iterations) {
              return text[index];
            }
            return chars[Math.floor(Math.random() * chars.length)];
          })
          .join("")
      );

      if (iterations >= text.length) {
        clearInterval(interval);
        setIsScrambling(false);
      }

      iterations += 1 / 2; // Speed of decoding (lower is slower)
    }, 40); // Tick rate
  };

  useEffect(() => {
    const timer = setTimeout(() => {
        scramble();
    }, delay);
    return () => clearTimeout(timer);
  }, []);

  return (
    <span 
        onMouseEnter={scramble} 
        className={`inline-block cursor-default ${className}`}
    >
      {display}
    </span>
  );
};

